70	/** Resolve merch group id to grid cell value. Never embed the full merchGroup list in JSON. */
71	function resolveMerchGroupValue(merchGroupMap, id) {
72	  if (id == null || id === '') {
73	    return null;
74	  }
75	  const mg = merchGroupMap.get(String(id));
76	  if (mg) {
77	    const values = mg.dataValues || mg;
78	    return { title: values.mg_desc, mg_code: values.mg_code, id: values.mg_id };
79	  }
80	  return { data: id };
81	}
