98	    return whsePriceCache.value;
99	  }
100	  const rows = await sql.RFQWhse.findAll({
101	    attributes: ['RFQWhse_price'],
102	    limit: 1,
103	  });
104	  const value = rows[0]?.dataValues?.RFQWhse_price ?? null;
105	  whsePriceCache = { value, expiresAt: now + CACHE_TTL_MS };
106	  return value;
107	}
